#include <iostream>
#include <iomanip>

class Rectangle {
public:
    double width;
    double height;

    double area() const {
        return width * height;
    }

    bool isSquare() const {
        return width == height;
    }
};

void printInfo(const Rectangle& r) {
    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Area: " << r.area() << "\n";
    std::cout << "Square: " << (r.isSquare() ? "yes" : "no") << "\n";
}

int main() {
    double w, h;
    std::cin >> w >> h;
    Rectangle r;
    r.width = w;
    r.height = h;
    printInfo(r);
    return 0;
}

