#include <iostream>
#include <iomanip>

class Sensor {
public:
    double reading1;
    double reading2;

    double average() const {
        return (reading1 + reading2) / 2.0;
    }
};

void report(const Sensor& s) {
    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Average: " << s.average() << "\n";
}

int main() {
    double r1, r2;
    std::cin >> r1 >> r2;
    Sensor s;
    s.reading1 = r1;
    s.reading2 = r2;
    report(s);
    return 0;
}
